import{_ as a,o as t,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt0903.jpg",d="/images/lekt0902.jpg",u="/images/lekt0901.jpg",c=JSON.parse('{"title":"Lektion 9","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion09.md","filePath":"lektionen/lektion09.md"}'),o={name:"lektionen/lektion09.md"};function s(l,e,p,h,m,k){return t(),r("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-9" tabindex="-1">Lektion 9 <a class="header-anchor" href="#lektion-9" aria-label="Permalink to &quot;Lektion 9&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>9.1. Samāhāradvandva = सआहारद्वन्द्व (&quot;Zusammenfassungsdvandva&quot;)</li><li>9.2. Zur Bildung von Nominalstämmen <ul><li>9.2.1. -ka (taddhita)</li><li>9.2.2. -aka (kṛt), fem. oft -ikā</li></ul></li><li>9.3. Wortliste</li><li>9.4. Übung</li></ul><h2 id="_9-1-samaharadvandva-सआहारद्वन्द्व-zusammenfassungsdvandva" tabindex="-1">9.1. Samāhāradvandva = सआहारद्वन्द्व (&quot;Zusammenfassungsdvandva&quot;) <a class="header-anchor" href="#_9-1-samaharadvandva-सआहारद्वन्द्व-zusammenfassungsdvandva" aria-label="Permalink to &quot;9.1. Samāhāradvandva = सआहारद्वन्द्व (&quot;Zusammenfassungsdvandva&quot;)&quot;">​</a></h2><p>Wenn ein Dvandva ausdrücken soll, dass eine Reihe von Dingen usw. eine Einheit bilden, dann steht es im Allgemeinen im Singular neutrum:</p><p>z.B.</p><p>āhāra-nidrā-maithuna-bhayam = आहारनिद्रामैथुनभयम् bedeutet nicht einfech &quot;Nahrungsaufnahme (āhāra m.), Schlaf (nidrā f.), Paarung (maithuna n.) und Angst (bhaya n.)&quot;, sondern diese vier als Einheit, die das tierische Leben charakterisiert.</p><p>Neben dieser Grundregel zur Bildung von Samāhāradvandvas gibt es noch eine Reihe weiterer Regeln, die man bei Pāṇini 2,4,2-17 oder z.B. Mr. R. Kale, A higher Sanskrit grammar, reprint 1969, § 189 - 192 a findet. In den verschiedenen Stufen der Sprachentwicklung wurden nicht immer die gleichen Regeln eingehalten!</p><h2 id="_9-2-zur-bildung-von-nominalstammen" tabindex="-1">9.2. Zur Bildung von Nominalstämmen <a class="header-anchor" href="#_9-2-zur-bildung-von-nominalstammen" aria-label="Permalink to &quot;9.2. Zur Bildung von Nominalstämmen&quot;">​</a></h2><h3 id="_9-2-1-ka-taddhita" tabindex="-1">9.2.1. -ka (taddhita) <a class="header-anchor" href="#_9-2-1-ka-taddhita" aria-label="Permalink to &quot;9.2.1. -ka (taddhita)&quot;">​</a></h3><p>Das taddhita-Suffix -ka bildet u.a.</p><ol><li>Diminutiva (Verkleinerungsformen wie deutsch -chen, -lein, -li, -le):<br> putra m. &quot;Sohn&quot; » putraka m. = पुत्रक &quot;Söhnchen&quot;</li><li>Nomina, die eine annähernde Ähnlichkeit bezeichnen:<br> aśva m. &quot;Pferd&quot; » aśvaka m. = अश्वक &quot;Rösslein, ein dem Pferd ähnliches Ding&quot;</li><li>Nomina ohne Bedeutungsunterschied zum zugrundeliegenden Nomen:<br> putraka m. पुत्रक = putra m. पुत्र्</li><li>Nomina, die ausdrücken &quot;zum Begriff des Grundwortes in Beziehung stehend&quot;:<br> kāśi f. &quot;Benares&quot; » kāśika 3 = काशिक &quot;in Benares gebürtig, aus Benares stammend&quot;<br> rūpa n. &quot;Gestalt&quot; » rūpaka 3 = रूपक &quot;die Gestalt von etwas besitzend&quot;</li></ol><h3 id="_9-2-2-aka-krt-fem-oft-ika" tabindex="-1">9.2.2. -aka (kṛt), fem. oft -ikā <a class="header-anchor" href="#_9-2-2-aka-krt-fem-oft-ika" aria-label="Permalink to &quot;9.2.2. -aka (kṛt), fem. oft -ikā&quot;">​</a></h3><p>Das kṛt-Suffix -aka, femininum oft -ikā, bildet Nomina agentis (Nomina, die den Täter ausdrücken) zu jeder Wurzel.</p><p>Ein auslautender Vokal der Worzel sowie -a- an vorletzter Stelle der Wurzel werden durch ihre Dehnstufe (vṛddhi) ersetzt (es gibt einige Ausnahmen), die übrigen Vokale werden durch ihre Dehnstufe (guṇa) ersetzt.</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -aka /ikā (kṛt)</th></tr></thead><tbody><tr><td>kṛ 8 U &quot;machen&quot;</td><td></td></tr><tr><td>कृ</td><td>kār-aka &quot;machend, Bewirker&quot;</td></tr><tr><td>कारक</td><td></td></tr><tr><td>śru 5 P &quot;hören&quot;</td><td></td></tr><tr><td>श्रु</td><td>(śrau-aka ») śrāv-aka m &quot;Hörer, Schüler, buddh.: Anhänger des Buddha&quot;</td></tr><tr><td>श्रावक</td><td></td></tr><tr><td>nī 1 U &quot;führen&quot;</td><td></td></tr><tr><td>नी</td><td>(nai-aka ») nāy-aka m. &quot;Führer, Gebieter, Gatte, Liebhaber&quot;</td></tr><tr><td>नायक</td><td></td></tr><tr><td>(nai-ikā ») nāy-ikā f. &quot;Geliebte, Dame&quot;</td><td></td></tr><tr><td>नायिका</td><td></td></tr></tbody></table><p>| | yaj 1 U &quot;opfern&quot;<br> यज् | yājaka m. &quot;Opferer, Opferpriester&quot;<br> याजक | | nṛt 4 P &quot;tanzen&quot;<br> नृत् | nart-aka m. Tänzer<br> नर्तक</p><p>nart-akī f. Tänzerin<br> नर्तकी</p><p>| | ji 1 P &quot;siegen&quot;<br> जि | jayaka 3 &quot;siegreich&quot;<br> जयक |</p><p>Einige dieser Bildungen haben die engere Bedeutung: &quot;das durch die Wurzel ausgedrückte gewohnheitsmäßig oder als Obliegenheit oder gut vollziehend&quot;</p><p>siehe oben z.B. śrāvaka, yājaka, jayaka</p><p>Beispiele:</p><table tabindex="0"><thead><tr><th>Wurzel</th><th>+ -aka /ikā (kṛt)</th></tr></thead><tbody><tr><td>kṛṣ 6 U &quot;pflügen&quot;</td><td></td></tr><tr><td>कृष्</td><td>kṛṣ-aka m. (tiefstufig!) &quot;Ackerbauer&quot;</td></tr><tr><td>कृषक</td><td></td></tr><tr><td>kliś 9 P &quot;quälen&quot;</td><td></td></tr><tr><td>क्लिश्</td><td>kleś-aka m. &quot;Quäler&quot;</td></tr><tr><td>क्लेशक</td><td></td></tr><tr><td>khād 1 P &quot;kauen, essen&quot;</td><td></td></tr><tr><td>खाद्</td><td>khād-aka m. &quot;Esser, Fresser&quot;</td></tr><tr><td>खादक</td><td></td></tr></tbody></table><p>Daneben gibt es noch einige weniger wichtigere Verwendungen des Suffixes -aka. Vgl. Wackernagel, Altindische Grammatik, II, §45ff.</p><h2 id="_9-3-wortliste" tabindex="-1">9.3. Wortliste <a class="header-anchor" href="#_9-3-wortliste" aria-label="Permalink to &quot;9.3. Wortliste&quot;">​</a></h2><p>Lernen Sie folgende Wörter:</p><p>adhyayana n अध्ययन : Lernen, insbes. Vedastudium</p><p><img src="'+i+'" alt=""><br> Abb.: adhyayana = अध्ययन, Sri Skandaguru Vidyalayam, Tiruparankundram bei Madurai<br> [Bildquelle: jaroslavd. -- <a href="http://www.flickr.com/photos/jaroslavd/2679883828/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jaroslavd/2679883828/</a> . -- Zugriff am 2008-11-23. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)</p><p>kāru m. / kāruka m. कारु कारुक : Handwerker</p><p><img src="'+d+'" alt=""><br> Abb.: kāru = कारु, Gujarat<br> [Bildquelle: owenstache. -- <a href="http://www.flickr.com/photos/owen-pics/2331791031/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/owen-pics/2331791031/</a>. -- Zugriff am 2008-11-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>kuśīlava m. कुशीलव : (fahrender) Schausteller, Schauspieler, Sänger</p><p>kusīda n. कुसीद : Wucher</p><p>kṛṣ 1 P (karṣati) कृष् कर्षति : ziehen</p><p>kṛṣ 6 U (kṛṣati) कृष् कृषति : pflügen</p><p>davon:</p><p>kṛṣi f. / kṛṣikā f. कृषि कृषिका : Ackerbau</p><p>dāna n. दान : Geben, Gabe, Freigebigkeit</p><p>pratigraha m. प्रतिग्रह : Empfangen, Geschenk</p><p>pravacana n. प्रवचन : Rede, (mündlicher) Unterricht</p><p>pāśupālya n. पाशुपाल्य : Viehhaltung, Viehzucht</p><p>zu yaj 1 U:</p><p>ijyā f. इज्या : Opfer (aus *yj » ij + Suffix yā)</p><p>yajana n. यजन : Opfer im Auftrag von jemand anderem</p><p>rūpa n. रूप : Aussehen, Form, schöne Form, Natur, Wesen</p><p>vāṇijya n. / vāṇijyā f. / vaṇijyā f. वाणिज्य वाणिज्या वणिज्या : Handel</p><p>śuśrūṣā f. शुश्रूषा : Gehorsam, gehorsamer Dienst</p><h2 id="_9-4-ubung" tabindex="-1">9.4. Übung <a class="header-anchor" href="#_9-4-ubung" aria-label="Permalink to &quot;9.4. Übung&quot;">​</a></h2><p>A) Versuchen Sie, die möglichen Bedeutungen folgender Wörter zu bestimmen:</p><p>1. brāhmānaka ब्राह्मणक</p><p>2. mati मति</p><p>3. śravaṇa श्रवण</p><p>4. dhenuka m. धेनुक</p><p>5. jayaka जयक</p><p>6. rakṣikā रक्षिका</p><p>7. karṣaka कर्षक</p><p><img src="'+u+'" alt=""><br> Abb.: karṣaka = कर्षक<br> [Bildquelle: Ray Witlin / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2183985518/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2183985518/</a>. -- Zugriff am 2008-11-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>8. kleśa क्लेश</p><p>9. nāyikātva नायिकात्व</p><p>10. tantraka तन्त्रक</p><p>11. nartaka (f. nartakī) नर्तक नर्तकी</p><p>12. naraka नरक</p><p>13. lābhaka लाभक</p><p>14. īśvaratā ईश्वरता</p><p>15. dhenukā f. धेनुका</p><p>16. yodhaka योधक</p><p>17. kopa कोप</p><p>18. veśaka वेशक</p><p>19. darśaka दर्शक</p><p>20. kopaka कोपक</p><p>B) Übersetzen Sie:</p><p>1. Aufgaben aller Zweimalgeborenen:</p><p>ijyādhyayanadānāni इज्याध्ययनदानानि</p><p>(Yājñavalkyadharmaśāstra I, 118)</p><p>2. Spezifische Aufgaben eines Brahmanen:</p><p>pravacanayājanapratigrahāḥ प्रवचनयाजनप्रतिग्रहाः</p><p>(Gautamadharmasūtra X,2)</p><p>3. Spezifische Aufgaben eines Kṣatriya:</p><p>rakṣaṇaṃ sarvabhūtānām रक्षणं सर्वभूतानाम्</p><p>(sarvabhūtānām = Genetiv (Wesfall): &quot;aller Wesen&quot;)</p><p>(Gautamadharmasūtra X,7)</p><p>4. Spezifische Aufgaben eines Vaiśya:</p><p>kṛṣivāṇijyapāśupālyakusīdam कृषिवाणिज्यपाशुपाल्यकुसीदम्</p><p>(nach Gautamadharmasūtra X,49)</p><p>5. Aufgaben eines Śūdra:</p><p>dvijātīnāṃ śuśrūṣā vārttā kārukuśīlavakarma ca. द्विजातीनं शुश्रूषा वार्त्त्ता कारुकुशीलवकर्म च</p><p>(nach Kauṭilīya-arthaśāstra 1.3.8.)</p><p>Erklärung:</p><p>dvijātīnām = Genetiv (Wesfall) Plural zu dvijāti (übersetzen Sie hier: &quot;gegenüber den Zweimalgeborenen&quot;)</p><p>kārukuśīlavakarma ist ein Tatpuruṣa mit einem Dvandva (kārukuśīlava) im Vorderglied. karma = Nom. sg. zu karman n. &quot;Tat, Tätigkeit, Karma&quot; zur Wurzel kṛ 8 U). Übersetzen Sie &quot;Tat / Tätigkeit der ... (Genetiv)&quot; (durch das Dvandva Bezeichneten).</p><p>6. kṛṣiḥ pāśupālyaṃ vaṇijyā ca vārttā. कृषिः पाशुपाल्यं वणिज्या च वार्त्ता |</p><p>(nach Kauṭilīya-arthaśāstra 1.4.1.)</p>',93)])])}const b=a(o,[["render",s]]);export{c as __pageData,b as default};
